// Parse Claude's JSON array; fall back to original rows if parse fails.
const resp = $input.first().json;
const text = resp?.content?.[0]?.text || '[]';
let cleaned = [];
try {
  const m = text.match(/\[[\s\S]*\]/);
  cleaned = JSON.parse(m ? m[0] : text);
} catch (e) {
  // If AI fails, use the upstream Classify rows unchanged
  const orig = $('Classify').first?.()?.json?.rows || [];
  cleaned = orig;
}
return [{ json: { rows: cleaned, count: cleaned.length, run_id: $('Normalize Body').item.json.run_id } }];
